Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/WhoIsToBeServedList/WhoIsToBeServed[./Value = " + WhoIsToBeServed.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/WhoIsToBeServedList/WhoIsToBeServed[./Description = " + WhoIsToBeServed.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

Javascript.transformToDisplay:
var description = Services.getValue( REF_DATA_XPATH + "/WhoIsToBeServedList/WhoIsToBeServed[./Value = " + WhoIsToBeServed.dataBinding + "]/Description" );
if (description != null)
{
	return description;
}
else
{
	return value;
}

Javascript.miscCode:
  	  
  WhoIsToBeServed.initialise = function() 
  { 
		dom = getList("../LOV/WhoIsToBeServedList.xml"); 
		Services.addNode(dom, REF_DATA_XPATH);
		return false; 
  }
  
  	WhoIsToBeServed.srcData 		= REF_DATA_XPATH + "/WhoIsToBeServedList";
	WhoIsToBeServed.rowXPath 	  	= "WhoIsToBeServed";
	WhoIsToBeServed.keyXPath 	  	= "Value";
	
	function WhoIsToBeServedLOVButton() {}
	WhoIsToBeServedLOVButton.tabIndex = __tabIdx++;
	
	function WhoIsToBeServedLOVGrid() {};
	WhoIsToBeServedLOVGrid.dataBinding = WhoIsToBeServed.dataBinding;
	WhoIsToBeServedLOVGrid.srcData 	   = REF_DATA_XPATH + "/WhoIsToBeServedList";
	WhoIsToBeServedLOVGrid.rowXPath    = "WhoIsToBeServed";
	WhoIsToBeServedLOVGrid.keyXPath    = "Value";
	WhoIsToBeServedLOVGrid.columns     = [
		{xpath: "Value"},
		{xpath: "Description"}
	];
	WhoIsToBeServedLOVGrid.raise = {
		eventBinding: {
			singleClicks: [ {element: "WhoIsToBeServedLOVButton"} ],
			keys: [ { key: Key.F6, element: "WhoIsToBeServed" } ]
		}
	};
